import { ethers } from 'ethers';
import { 
  EXPORT_ABI, 
  IMPORT_ABI, 
  IMPORT_WRAPPER_ABI 
} from '../contracts/abi';
import { autoDetectToken } from './token-detector';
import { NETWORKS } from '../config/networks';

/**
 * Bridge type detection based on constructor parameters
 */
export const BRIDGE_TYPES = {
  EXPORT: 'export',
  IMPORT: 'import',
  IMPORT_WRAPPER: 'import_wrapper'
};

/**
 * Detect bridge type by analyzing constructor parameters
 * @param {ethers.providers.Provider} provider - Web3 provider
 * @param {string} bridgeAddress - Bridge contract address
 * @returns {Promise<string>} Bridge type (export, import, import_wrapper)
 */
export const detectBridgeType = async (provider, bridgeAddress) => {
  try {
    // Try each bridge type and check if the contract responds
    const bridgeTypes = [
      { type: BRIDGE_TYPES.EXPORT, abi: EXPORT_ABI },
      { type: BRIDGE_TYPES.IMPORT, abi: IMPORT_ABI },
      { type: BRIDGE_TYPES.IMPORT_WRAPPER, abi: IMPORT_WRAPPER_ABI }
    ];

    for (const { type, abi } of bridgeTypes) {
      try {
        const contract = new ethers.Contract(bridgeAddress, abi, provider);
        
        // Try to call a function that exists on this bridge type
        switch (type) {
          case BRIDGE_TYPES.EXPORT:
            await contract.foreign_network();
            return type;
          case BRIDGE_TYPES.IMPORT:
            await contract.home_network();
            return type;
          case BRIDGE_TYPES.IMPORT_WRAPPER:
            await contract.home_network();
            return type;
          default:
            throw new Error(`Unsupported bridge type: ${type}`);
        }
      } catch (error) {
        // Continue to next bridge type
        continue;
      }
    }
    
    throw new Error('Unable to detect bridge type');
  } catch (error) {
    console.error('Error detecting bridge type:', error);
    throw new Error(`Failed to detect bridge type: ${error.message}`);
  }
};

/**
 * Get bridge data from Export contract
 * @param {ethers.providers.Provider} provider - Web3 provider
 * @param {string} bridgeAddress - Bridge contract address
 * @param {string} networkSymbol - Network where bridge is deployed
 * @returns {Promise<Object>} Bridge configuration data
 */
export const getExportBridgeData = async (provider, bridgeAddress, networkSymbol) => {
  try {
    const contract = new ethers.Contract(bridgeAddress, EXPORT_ABI, provider);
    
    const [
      foreignNetwork,
      foreignAsset,
      settings
    ] = await Promise.all([
      contract.foreign_network(),
      contract.foreign_asset(),
      contract.settings()
    ]);

    const { tokenAddress: stakeTokenAddress } = settings;

    // Get stake token symbol using token detector
    let stakeTokenSymbol = null;
    try {
      const stakeTokenResult = await autoDetectToken(provider, stakeTokenAddress, networkSymbol);
      if (stakeTokenResult.success) {
        stakeTokenSymbol = stakeTokenResult.tokenInfo.symbol;
      }
    } catch (error) {
      console.warn('Failed to detect stake token symbol:', error);
    }

    return {
      foreignNetwork,
      foreignAsset,
      stakeTokenAddress,
      stakeTokenSymbol
    };
  } catch (error) {
    console.error('Error getting Export bridge data:', error);
    throw new Error(`Failed to get Export bridge data: ${error.message}`);
  }
};

